import{_ as s,C as t,o as d,c as p,j as e,a as n,E as i,a3 as u}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"庄子·养生主","description":"以庖丁解牛为核心，讲在复杂世界中顺势而行与保全天年之道。","frontmatter":{"title":"庄子·养生主","description":"以庖丁解牛为核心，讲在复杂世界中顺势而行与保全天年之道。","category":"guide","aliases":["养生主","庄子养生主","zhuangzi chapter 03"],"source":["《庄子》","维基文库：庄子·养生主"]},"headers":[],"relativePath":"daoism/texts/zhuang-zi/chapter-03.md","filePath":"daoism/texts/zhuang-zi/chapter-03.md","lastUpdated":1778126077000}'),c={name:"daoism/texts/zhuang-zi/chapter-03.md"};function x(m,a,b,f,_,g){const r=t("DaoReadingPrelude"),l=t("DaoOriginalReadingGroup"),o=t("DaoLineGuide"),h=t("DaoKeywordCards");return d(),p("div",null,[a[0]||(a[0]=e("h1",{id:"庄子·养生主",tabindex:"-1"},[n("庄子·养生主 "),e("a",{class:"header-anchor",href:"#庄子·养生主","aria-label":'Permalink to "庄子·养生主"'},"​")],-1)),i(r,{title:"从庖丁解牛，看庄子如何说养生",summary:"养生主是《庄子》内篇中最短的一篇，只有五个小节，但庖丁解牛这一段是庄子全书最著名的寓言之一。这一篇的「养生」不是保养身体，而是养「生之主」——那个让人得以在纷繁复杂的世界中不受伤害的核心力量。",points:[{label:"先看",text:"顺着原文看五个小节：总纲→庖丁解牛→右师独脚→泽雉不畜樊中→老聃之死。"},{label:"再问",text:"庖丁说「以无厚入有间」——用在今天，什么是你生活中那条「有间」之路？"},{label:"最后",text:"「安时而处顺，哀乐不能入」是什么意思？和逃避有什么不同？"}],hint:"养生主虽短但每一节都有一个具体的练习：你可以用庖丁解牛来对照自己的工作方式，用泽雉的比喻来反思自己的「樊笼」。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[n("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(l,{paragraphs:["吾生也有涯，而知也无涯。以有涯随无涯，殆已；已而为知者，殆而已矣。为善无近名，为恶无近刑。缘督以为经，可以保身，可以全生，可以养亲，可以尽年。","庖丁为文惠君解牛，手之所触，肩之所倚，足之所履，膝之所踦，砉然向然，奏刀騞然，莫不中音。合于《桑林》之舞，乃中《经首》之会。文惠君曰：「嘻！善哉！技盖至此乎？」庖丁释刀对曰：「臣之所好者道也，进乎技矣。始臣之解牛之时，所见无非牛者。三年之后，未尝见全牛也。方今之时，臣以神遇，而不以目视，官知止而神欲行。依乎天理，批大郤，导大窾，因其固然。技经肯綮之未尝，而况大軱乎！良庖岁更刀，割也；族庖月更刀，折也。今臣之刀十九年矣，所解数千牛矣，而刀刃若新发于硎。彼节者有间，而刀刃者无厚，以无厚入有间，恢恢乎其于游刃必有余地矣，是以十九年而刀刃若新发于硎。虽然，每至于族，吾见其难为，怵然为戒，视为止，行为迟。动刀甚微，謋然已解，如土委地。提刀而立，为之四顾，为之踌躇满志，善刀而藏之。」文惠君曰：「善哉！吾闻庖丁之言，得养生焉。」","公文轩见右师而惊曰：「是何人也？恶乎介也？天与，其人与？」曰：「天也，非人也。天之生是使独也，人之貌有与也。以是知其天也，非人也。」","泽雉十步一啄，百步一饮，不蕲畜乎樊中。神虽王，不善也。","老聃死，秦失吊之，三号而出。弟子曰：「非夫子之友邪？」曰：「然。」「然则吊焉若此，可乎？」曰：「然。始也，吾以为其人也，而今非也。向吾入而吊焉，有老者哭之，如哭其子；少者哭之，如哭其母。彼其所以会之，必有不蕲言而言，不蕲哭而哭者。是遁天倍情，忘其所受，古者谓之遁天之刑。适来，夫子时也；适去，夫子顺也。安时而处顺，哀乐不能入也，古者谓是帝之县解。」","指穷于为薪，火传也，不知其尽也。"]}),i(o,{lines:[{label:"总纲",text:"「吾生也有涯，而知也无涯」至「缘督以为经」——以有涯随无涯是危险的，庄子给出的方案是「缘督以为经」，顺中道而行。"},{label:"庖丁解牛",text:"全篇最核心的寓言——从「所见无非牛」到「未尝见全牛」再到「以神遇而不以目视」，展示从技巧到道的过程。"},{label:"以无厚入有间",text:"刀之所以十九年如新，不是因为刀硬，而是因为刀总能找到骨节的缝隙。这是庄子式「养生」的核心隐喻。"},{label:"怵然为戒",text:"遇到难解之处时，庖丁不是硬砍而是「怵然为戒」——最熟练的人反而最谨慎。"},{label:"右师独脚",text:"公文轩问右师为什么只有一只脚——是天生的还是人为的？答案是「天也，非人也」——接受命运中不可改变的部分。"},{label:"泽雉",text:"野鸡十步一啄、百步一饮，虽辛苦但不求樊笼中的安逸——「神虽王，不善也」。"},{label:"老聃之死",text:"秦失吊老聃，三号而出——「安时而处顺，哀乐不能入也」。这是庄子面对死亡的姿态。"},{label:"薪尽火传",text:"薪柴烧尽了，火却传下去——生死的边界在哪？这是养生主的最终叩问。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[n("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),i(h,{items:[{term:"涯",pinyin:["yá"],explanation:"边界、尽头。生有涯而知无涯——以有限的生命追逐无限的知识，本身就是危险的。"},{term:"督",pinyin:["dū"],explanation:"中道、正中。缘督以为经，意为顺着中道而行，不强求、不偏执。"},{term:"砉",pinyin:["huā"],explanation:"象声词，皮骨剥离的声音。庖丁解牛时手触、肩倚、足履、膝踦，每一个动作都有节奏。"},{term:"騞",pinyin:["huō"],explanation:"刀裂物的声音。砉然向然，奏刀騞然——刀法的声音与《桑林》之舞、《经首》之乐相合。"},{term:"郤",pinyin:["xì"],explanation:"同「隙」，骨节间的空隙。批大郤，指顺着骨头之间的大缝隙下刀。"},{term:"窾",pinyin:["kuǎn"],explanation:"空处。导大窾，指把刀引入骨节间的大空隙。"},{term:"肯綮",pinyin:["kěn","qìng"],explanation:"筋骨结合处。「技经肯綮之未尝」——连筋骨结合处都没有碰到过，说明刀刃之精准。"},{term:"軱",pinyin:["gū"],explanation:"大骨。「而况大軱乎」——连筋结都碰不到，更不用提大骨头了。"},{term:"謋",pinyin:["huò"],explanation:"骨肉分离的声音。謋然已解，如土委地——牛被解开时轻描淡写，像土块落地。"},{term:"县解",pinyin:["xuán","jiě"],explanation:"「悬解」，摆脱束缚。帝之县解，指摆脱生死哀乐之缚，是庄子对「解脱」的独特表达。"}]}),a[3]||(a[3]=u('<h2 id="【原典层】原文底本" tabindex="-1">【原典层】原文底本 <a class="header-anchor" href="#【原典层】原文底本" aria-label="Permalink to &quot;【原典层】原文底本&quot;">​</a></h2><ul><li><a href="https://ctext.org/zhuangzi/nourishing-the-lord-of-life/zh" target="_blank" rel="noreferrer">维基文库：庄子·养生主</a></li><li>所属：内篇</li><li>次序：内篇第三篇</li></ul><h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一篇在说什么" tabindex="-1">象：这一篇在说什么 <a class="header-anchor" href="#象-这一篇在说什么" aria-label="Permalink to &quot;象：这一篇在说什么&quot;">​</a></h3><p>养生主以「有涯随无涯则殆」为总纲，提出「缘督以为经」的养生之道。庖丁解牛是全篇的核心——一个厨子解牛十九年而刀刃如新，不是刀硬，而是因为他总能找到骨节间的「缝隙」。后面的右师独脚、泽雉不畜樊中、老聃之死、薪尽火传四个小节，分别从接受天命、不慕樊笼、安时处顺、生死贯通四个角度深化了「养生主」的含义。</p><h3 id="理-为什么这一篇重要" tabindex="-1">理：为什么这一篇重要 <a class="header-anchor" href="#理-为什么这一篇重要" aria-label="Permalink to &quot;理：为什么这一篇重要&quot;">​</a></h3><p>养生主虽然短，但它在庄子思想中占据关键位置。为什么重要？第一，它在「逍遥游」的自由想象和「齐物论」的哲学追问之后，给出了一个非常具体的实践路径——「以无厚入有间」；第二，它将「养生」从身体保养提升为「养生之主」，即养护那个让人不受伤害的核心力量；第三，庖丁解牛不是让人变得「硬」，而是让人变得「敏锐」——最熟练的人恰恰最谨慎（怵然为戒）。</p><h3 id="用-今天怎么进入这一篇" tabindex="-1">用：今天怎么进入这一篇 <a class="header-anchor" href="#用-今天怎么进入这一篇" aria-label="Permalink to &quot;用：今天怎么进入这一篇&quot;">​</a></h3><p>今天用养生主，可以从庖丁解牛入手。想一想：你工作和生活中，哪些冲突是因为你在「硬砍」而不是在「找缝隙」？有什么事情，如果你换一个角度（找对「郤」和「窾」），就可以不费力地解决？泽雉那一节也很实用——你有没有因为贪图「樊笼中的安逸」（稳定的焦虑、被需要的虚荣）而放弃了本来可以更自由的状态？最后一节老聃之死，可以和对死亡、告别、放手的思考结合起来理解。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《庄子》</li><li><a href="https://ctext.org/zhuangzi/nourishing-the-lord-of-life/zh" target="_blank" rel="noreferrer">维基文库：庄子·养生主</a></li></ul>',15))])}const P=s(c,[["render",x]]);export{q as __pageData,P as default};
